package main

import (
    "flag"
    "fmt"
    "golang.org/x/crypto/sha3"
    "os"
)

var (
    logoSHA1024 = `
dd`

    fileName   string
    shaOptions []struct {
        name string
        desc string
        shaLength int
        enabled *bool
    }
)

func init() {
    flag.StringVar(&fileName, "f", "", "[nazwa pliku]")

    shaOptions = []struct {
        name string
        desc string
        shaLength int
        enabled *bool
    }{
        {"-sha1024", "[generuj skrót SHA-1024]", 128, new(bool)},
        {"-sha2048", "[generuj skrót SHA-2048]", 256, new(bool)},
        {"-sha4096", "[generuj skrót SHA-4096]", 512, new(bool)},
        {"-sha8192", "[generuj skrót SHA-8192]", 1024, new(bool)},
        {"-sha16384", "[generuj skrót SHA-16384]", 2048, new(bool)},
        {"-sha32768", "[generuj skrót SHA-32768]", 4096, new(bool)},
        {"-sha65536", "[generuj skrót SHA-65536]", 8192, new(bool)},
    }

    flag.Usage = func() {
        fmt.Fprintf(os.Stderr, "%s\n", logoSHA1024)
        fmt.Fprintf(os.Stderr, "\n")
        fmt.Fprintf(os.Stderr, "Generates SHA hashes 1024-65536 for the file using the SHA-3 Shake256 algorithm.\n")
        fmt.Fprintf(os.Stderr, "\n")
        fmt.Fprintf(os.Stderr, "Sposób użycia: %s -f [nazwa_pliku] [opcje]\n", os.Args[0])
        fmt.Fprintf(os.Stderr, "\nOpcje:\n")
        for _, shaOption := range shaOptions {
            fmt.Fprintf(os.Stderr, "%s %s\n", shaOption.name, shaOption.desc)
        }
    }

    flag.Parse()
}

func main() {
    if fileName == "" {
        flag.Usage()
        os.Exit(1)
    }

    buf := []byte(fileName)

    for _, shaOption := range shaOptions {
        if *shaOption.enabled {
            h := make([]byte, shaOption.shaLength)
            sha3.ShakeSum256(h, buf)
            fmt.Printf("%s: %x\n", shaOption.name, h)
        }
    }
}

