  int enters_sum = 0; // сумма чисел после слова Enters
  int exits_sum = 0; // сумма чисел после слова Exits

  while (getline(file, line)) { // читаем строки из файла по очереди
    size_t enters_pos = line.find("Enters=\""); // ищем позицию слова Enters
    if (enters_pos != string::npos) { // если слово найдено
      enters_pos += 8; // перемещаемся за слово и кавычку
      size_t enters_end = line.find("\"", enters_pos); // ищем позицию закрывающей кавычки
      if (enters_end != string::npos) { // если кавычка найдена
        string enters_str = line.substr(enters_pos, enters_end - enters_pos); // выделяем строку с числом
        int enters_num = stoi(enters_str); // преобразуем строку в число
        enters_sum += enters_num; // добавляем число к сумме
      }
    }

    size_t exits_pos = line.find("Exits=\""); // ищем позицию слова Exits
    if (exits_pos != string::npos) { // если слово найдено
      exits_pos += 7; // перемещаемся за слово и кавычку
      size_t exits_end = line.find("\"", exits_pos); // ищем позицию закрывающей кавычки
      if (exits_end != string::npos) { // если кавычка найдена
        string exits_str = line.substr(exits_pos, exits_end - exits_pos); // выделяем строку с числом
        int exits_num = stoi(exits_str); // преобразуем строку в число
        exits_sum += exits_num; // добавляем число к сумме
      }
    }
  }

  file.close(); // закрываем файл

  cout << "Enters sum: " << enters_sum << endl;
  cout << "Exits sum: " << exits_sum << endl;

  return 0;
}

