        self.__nomMG = nomMG

    def set_prenomMG(self, prenomMG):
        self.__prenomMG = prenomMG

    def set_nomDeSceneMG(self, nomDeSceneMG):
        self.__nomDeSceneMG = nomDeSceneMG

