datetime prevnbtime;

bool isNewBar(int tf)
{
   bool res = false;

   if(tf >= 0)
   {
      if(iTime(NULL,tf,0) != prevnbtime)
      {
      res   = true;
      prevnbtime = iTime(NULL,tf,0);
      }   
   }
   else res = true;

   return(res);
}

string prevmess;

bool BoxAlert(bool cond,string text)   
{      
